+function markFileHandleClosedSync(handle: fs.FileHandle): void {
+  const mutableHandle = handle as unknown as Record<PropertyKey, unknown>;
+  for (const key of Reflect.ownKeys(handle)) {
+    if (typeof key !== "symbol") {
+      continue;
